            } else if (digits > 0) {
                // Break if we already started counting digits and find an invalid character
                break;
            }
        }

        // Calculate the unsigned and signed sums
        unsignedSum += (b & 0xFF); // Ensure unsigned handling
        signedSum += b; // Signed sum remains unchanged
    }

    // Compare the calculated checksums with the stored one
    return storedSum == unsignedSum || storedSum == signedSum;
}
